                            loop_counts[target_id] = 0  # reset
                            node_outputs[target_id] = output  # pass through
                            # Record loop counter hit
                            trace.steps.append(NodeExecution(
                                node_id=target_id,
                                node_type="loop_counter",
                                iteration=count,
                                input_text=f"loop exhausted ({count}/{max_iter})",
                                output_text=output,
                            ))
